<template>
    <div class="my-popups">
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered ui-draggable mw-800">
                <div class="modal-content" v-if="deviceRecord.online">
                    <div class="modal-header ui-draggable-handle">
                        <h5 class="modal-title">
                            Edit Device: Main Entrance Kiosk
                        </h5>
                        <button class="close" @click="handleClose">
                            <em class="fa fa-times"></em>
                        </button>
                    </div>
                    <div class="modal-body">
                        <section class="main-content">
                            <div class="container-fluid p-0">
                                <div class="tab-style">
                                    <div class="tab_container mb-0">
                                        <ul class="nav nav-tabs all-tabs responsive-tabs cust flex-wrap newtabbb">
                                            <li class="nav-item">
                                                <a data-toggle="tab" @click="activeTab = 'details'"
                                                    class="nav-link active">Device Details</a>
                                            </li>

                                            <li class="nav-item" v-if="deviceRecord.apiUrl">
                                                <a data-toggle="tab" @click="activeTab = 'remote'"
                                                    class="nav-link">Remote Logs</a>
                                            </li>
                                            <li class="nav-item">
                                                <a data-toggle="tab" @click="activeTab = 'deviceLog'"
                                                    class="nav-link">Device Logs</a>
                                            </li>
                                        </ul>
                                    </div>
                                </div>
                                <div class="border container-fluid float-left">
                                    <!-- Device Details Tab -->
                                    <div class="tab-content mt-3" v-show="activeTab === 'details'">
                                        <form id="deviceForm">
                                            <div class="row">
                                                <div class="col-sm-12 col-md-12 float-left col-lg-6 col-xl-6">
                                                    <div class="form-group">
                                                        <label for="deviceName">Device Name:<span
                                                                class="text-danger">*</span></label>
                                                        <span class="d-flex">
                                                            <input type="text" id="deviceName" class="form-control"
                                                                placeholder="e.g., Main Entrance Kiosk" required
                                                                v-model="deviceForm.deviceName"
                                                                @input="clearError('deviceName')" />
                                                            <small v-if="errors.deviceName" class="text-danger">{{
                                                                errors.deviceName }}</small>
                                                        </span>
                                                    </div>
                                                </div>
                                                <div class="col-sm-12 col-md-12 float-left col-lg-6 col-xl-6">
                                                    <div class="form-group">
                                                        <label for="deviceId">Device ID:<span
                                                                class="text-danger">*</span></label>
                                                        <span class="d-flex">
                                                            <input type="text" id="deviceId" class="form-control"
                                                                placeholder="e.g., KIOSK-001" required
                                                                v-model="deviceForm.uniqueCode"
                                                                @input="clearError('uniqueCode')" />
                                                            <small v-if="errors.uniqueCode" class="text-danger">{{
                                                                errors.uniqueCode }}</small>
                                                        </span>
                                                    </div>
                                                </div>
                                                <div class="col-sm-12 col-md-12 float-left col-lg-6 col-xl-6">
                                                    <div class="form-group">
                                                        <label for="deviceModel">Device Model:</label>
                                                        <span class="d-flex">
                                                            <input type="text" id="deviceModel" class="form-control"
                                                                placeholder="e.g., Samsung Tab A7"
                                                                v-model="deviceForm.deviceModel" />
                                                        </span>
                                                    </div>
                                                </div>
                                                <div class="col-sm-12 col-md-12 float-left col-lg-6 col-xl-6">
                                                    <div class="form-group">
                                                        <label for="location">Location:<span
                                                                class="text-danger">*</span></label>
                                                        <span class="d-flex">
                                                            <input type="text" id="location" class="form-control"
                                                                placeholder="e.g., Main Lobby" required
                                                                v-model="deviceForm.subLocation"
                                                                @input="clearError('subLocation')" />
                                                            <small v-if="errors.subLocation" class="text-danger">{{
                                                                errors.subLocation }}</small>
                                                        </span>
                                                    </div>
                                                </div>
                                                <div class="col-sm-12 col-md-12 float-left col-lg-12 col-xl-12">
                                                    <div class="form-group">
                                                        <label for="apiUrl">Face Auth Service URL:
                                                            <!-- <span
                                                                class="text-danger">*</span> -->
                                                        </label>
                                                        <input type="url" id="apiUrl" class="form-control"
                                                            placeholder="http://localhost:5000/face-auth" required
                                                            v-model="deviceForm.apiUrl" @input="clearError('apiUrl')" />
                                                        <small v-if="errors.apiUrl" class="text-danger">{{
                                                            errors.apiUrl }}</small>
                                                        <small class="text-secondary">URL of the local face
                                                            authentication service</small>
                                                    </div>
                                                </div>
                                                <!-- <div class="col-sm-12 col-md-12 float-left col-lg-6 col-xl-6">
                                                    <div class="form-group">
                                                        <label for="syncFrequency">Sync Frequency (minutes):</label>
                                                        <span class="d-flex">
                                                            <input type="number" id="syncFrequency" class="form-control"
                                                                value="15" min="5" max="1440"
                                                                v-model.number="deviceForm.syncFrequency" />
                                                        </span>
                                                    </div>
                                                </div> -->
                                                <div class="col-sm-12 col-md-12 float-left col-lg-6 col-xl-6">
                                                    <div class="form-group">
                                                        <label for="deviceStatus">Status:</label>
                                                        <select id="deviceStatus" class="form-control"
                                                            v-model="deviceForm.statusId">
                                                            <option :value="1001">Active</option>
                                                            <option :value="1002">Inactive</option>
                                                        </select>
                                                    </div>
                                                </div>

                                                <tg-list v-if="deviceForm.statusId === 1001" ref="tglistuser"
                                                    :IsShowAction="false" :showCheckBox="false" :listType="['List']"
                                                    ModuleName="Company" SubModuleCode="CMP_USER"
                                                    IdentityColumn="user_id" HeaderText="Scheduler Details"
                                                    :ListData="scheduleTimes" :HeaderData="Headers"
                                                    :NorecordfoundText="$t('NoRecordfound')" :IsFilterApplied="false">
                                                    <template v-slot:slotdata="{ data }">
                                                        <template v-if="data.column.COLUMN_NAME === 'action'">
                                                            <button type="button"
                                                                class="btn btn-run-schedule btn-table-action"
                                                                title="Force Fully Run" @click="forceRun(data.row)">
                                                                <i class="fa fa-play mr-1"></i>
                                                                Force Fully Run
                                                            </button>
                                                        </template>

                                                    </template>
                                                </tg-list>
                                                <div v-else class="alert alert-warning mt-3">
                                                    Device is Inactive. Schedule is not available.
                                                </div>

                                            </div>

                                            <div class="col-12 mt-3 p-0 mb-3">
                                                <div class="row flex-row-reverse">

                                                    <div class="col-lg-6 col-md-6 text-right">
                                                        <button type="button" id="submitForm" class="btn btn-success"
                                                            @click="submitForm()"><i
                                                                class="fa fa-save pr-2"></i>Save</button>
                                                        <button type="button" id="cancelForm" class="btn btn-danger"
                                                            style="margin-left: 5px;" @click="handleClose()"><i
                                                                class="fa fa-close pr-2"></i>Cancel</button>
                                                    </div>
                                                    <div class="col-lg-6 col-md-6">
                                                        <div class="py-2 mandatory">Fields marked with an asterisk (*)
                                                            are mandatory.</div>
                                                    </div>
                                                </div>
                                            </div>
                                        </form>
                                    </div>



                                    <!-- Remote Logs Tab -->
                                    <div class="tab-content mt-3" v-show="activeTab === 'remote'">
                                        <div class="col-lg-12 mb-3 p-0">
                                            <div class="heading-border mt-2">
                                                <h5 class="h5"><span>Live logs from the selected kiosk device</span>
                                                </h5>
                                                <!-- <h5 class="h5"><span>Remote Device Logs</span></h5> -->
                                            </div>

                                            <!-- <span class="input-group w-100" style="flex-wrap: nowrap;">
                                              <input autocomplete="off" name="planned_start_date" placeholder="Plan Start Date" class="form-control w-100">
                                              <div class="input-group-append">
                                                 <span class="input-group-text"><i class="fa fa-calendar"></i></span>
                                              </div>
                                              <div data-v-bbffc602="" class="vc-popover-content-wrapper is-interactive" style=""></div>
                                           </span> -->

                                            <div class="col-lg-12 mt-3 p-0">
                                                <v-date-picker v-model="selectedDate" :masks="{ input: 'YYYY-MM-DD' }"
                                                    @input="filterLogs">
                                                    <template v-slot="{ inputValue, inputEvents, togglePopover }">
                                                        <span class="input-group w-100" style="flex-wrap: nowrap;">

                                                            <input class="form-control w-100" :value="inputValue"
                                                                v-on="inputEvents" placeholder="Select date" readonly />

                                                            <div class="input-group-append">
                                                                <span class="input-group-text" @click="togglePopover"
                                                                    style="cursor: pointer;">
                                                                    <i class="fa fa-calendar"></i>
                                                                </span>
                                                            </div>

                                                            <button class="btn btn-primary ml-2 d-flex"
                                                                v-if="selectedDate"
                                                                @click="selectedDate = null; filterLogs();">
                                                                <em class="fa fa-refresh pt-1 pr-2"></em>Clear
                                                            </button>

                                                        </span>
                                                    </template>
                                                </v-date-picker>




                                                <!-- <input type="date" v-model="selectedDate" placeholder="Select date" @change="filterLogs" />
                                            <button v-if="selectedDate" @click="selectedDate = '';filterLogs()">
                                                Clear
                                            </button> -->
                                            </div>

                                            <div class="col-sm-12 col-lg-12 col-md-12 float-left mt-3 p-0">
                                                <ul class="remlogcont">
                                                    <li v-for="(log, index) in logs" :key="index">
                                                        {{ log }}
                                                    </li>
                                                </ul>
                                            </div>
                                        </div>
                                        <div class="col-12 mt-3 p-0 mb-3 float-left">
                                            <div class="row flex-row-reverse">
                                                <div class="col-lg-6 col-md-6 text-right">
                                                    <button type="button" id="refreshRemoteLogs" class="btn btn-info"
                                                        @click="refresh()"><i class="fa fa-sync-alt pr-2"></i>Refresh
                                                        Logs</button>
                                                    <button type="button" id="downloadLogs" class="btn btn-secondary"
                                                        style="margin-left: 5px;" @click="downloadLogs()"><i
                                                            class="fa fa-download pr-2"></i>Download Logs</button>
                                                </div>
                                            </div>
                                        </div>
                                    </div>

                                    <div class="tab-content mt-3" v-show="activeTab === 'deviceLog'">
                                        <div class="col-lg-12 mb-3 p-0">
                                            <div class="heading-border mt-2">
                                                <h5 class="h5"><span>Live device logs</span>
                                                </h5>
                                                <!-- <h5 class="h5"><span>Remote Device Logs</span></h5> -->
                                            </div>
                                            <div class="col-lg-12 mt-3 p-0">
                                                <v-date-picker v-model="selectedDeviceDate"
                                                    :masks="{ input: 'YYYY-MM-DD' }" @input="filterDeviceLogs">
                                                    <template v-slot="{ inputValue, inputEvents, togglePopover }">
                                                        <span class="input-group w-100" style="flex-wrap: nowrap;">

                                                            <input class="form-control w-100" :value="inputValue"
                                                                v-on="inputEvents" placeholder="Select date" readonly />

                                                            <div class="input-group-append">
                                                                <span class="input-group-text" @click="togglePopover"
                                                                    style="cursor: pointer;">
                                                                    <i class="fa fa-calendar"></i>
                                                                </span>
                                                            </div>

                                                            <button class="btn btn-primary ml-2 d-flex"
                                                                v-if="selectedDeviceDate"
                                                                @click="selectedDeviceDate = null; filterDeviceLogs();">
                                                                <em class="fa fa-refresh pt-1 pr-2"></em>Clear
                                                            </button>

                                                        </span>
                                                    </template>
                                                </v-date-picker>
                                            </div>

                                            <div class="col-sm-12 col-lg-12 col-md-12 float-left mt-3 p-0">
                                                <ul class="remlogcont">
                                                    <li v-for="(log, index) in deviceLogs" :key="index">
                                                        {{ log }}
                                                    </li>
                                                </ul>
                                            </div>
                                        </div>
                                        <div class="col-12 mt-3 p-0 mb-3 float-left">
                                            <div class="row flex-row-reverse">
                                                <div class="col-lg-6 col-md-6 text-right">
                                                    <button type="button" id="refreshRemoteLogs" class="btn btn-info"
                                                        @click="refreshDevice()"><i
                                                            class="fa fa-sync-alt pr-2"></i>Refresh
                                                        Logs</button>
                                                    <button type="button" id="downloadLogs" class="btn btn-secondary"
                                                        style="margin-left: 5px;" @click="downloadDeviceLogs()"><i
                                                            class="fa fa-download pr-2"></i>Download Logs</button>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </section>
                    </div>
                </div>
                <div class="modal-content text-center p-5" v-else>
                    <h4 class="text-danger">Device is Offline</h4>
                    <p>Please check the device connection.</p>
                    <button class="btn btn-danger mt-3" @click="handleClose">
                        Close
                    </button>
                </div>
            </div>
        </div>
    </div>
</template>


<script>
import DataService from '../../services/DataService';
export default {
    components: {

    },
    props: {
        deviceRecord: {
            type: Object,
            default: () => ({})
        }
    },
    data() {
        return {
            activeTab: 'details',
            logs: [],
            allLogs: [],
            allDeviceLogs: [],
            deviceLogs: [],
            selectedDate: null,
            selectedDeviceDate: null,

            deviceForm: {
                deviceName: '',
                uniqueCode: '',
                deviceModel: '',
                subLocation: '',
                apiUrl: '',
                syncFrequency: "Daily",
                statusId: null
            },
            scheduleTimes: [
            ],
            Headers: [
                {
                    COLUMN_NAME: "schedule_name",
                    DATA_TYPE: "text",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: "Schedule name",
                    DISPLAY_ORDER: 1,
                    settings: { isInSlot: false },
                },
                {
                    COLUMN_NAME: "schedule_type",
                    DATA_TYPE: "text",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: "Type",
                    DISPLAY_ORDER: 1,
                    settings: { isInSlot: false },
                },
                {
                    COLUMN_NAME: "start_date",
                    DATA_TYPE: "datetime",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: "Time",
                    DISPLAY_ORDER: 1,
                    settings: { isInSlot: false },
                },
                {
                    COLUMN_NAME: "action",
                    DATA_TYPE: "text",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: "Action",
                    DISPLAY_ORDER: 3,
                    settings: { isInSlot: true },
                }
            ],
            errors: {}

        };
    },
    sockets: {
        sendLogs(data) {
            try {
                const parsedLogs = JSON.parse(data.logs || "[]");

                // Convert to readable string if needed
                this.allLogs = parsedLogs.map(log =>
                    `[INFO] ${log.created_at} - ${log.message || "Log entry"}`
                );

                this.logs = [...this.allLogs];

            } catch (e) {
                console.error("Log parse error:", e);
                this.logs = [];
                this.allLogs = [];
            }
        },
        sendDeviceLogs(data) {
            try {

                // Safe optional chaining
                const parsedLogs = data?.logs?.logs;

                if (!Array.isArray(parsedLogs)) {
                    console.warn("Logs not in expected format");
                    this.deviceLogs = [];
                    this.allDeviceLogs = [];
                    return;
                }

                // Convert logs to readable format
                this.allDeviceLogs = parsedLogs.map(log => {
                    const time = log.time || "Unknown Time";
                    const message = log.message || "Log entry";
                    const level = log.level || "INFO";

                    return `[${level}] ${time} - ${message}`;
                });

                this.deviceLogs = [...this.allDeviceLogs];

            } catch (e) {
                console.error("Log parse error:", e);
                this.deviceLogs = [];
                this.allDeviceLogs = [];
            }
        },
        getScheduleFromMob(data) {
            ///console.log("Received schedule data:", data);

            try {
                this.scheduleTimes = JSON.parse(data.scheduleData || "[]");
            } catch (e) {
                console.error("Schedule parse error:", e);
                this.scheduleTimes = [];
            }
        },
        forcefullyRunResponse(data) {
            console.log("Received force run response:", data);
            const message = data.status
                ? this.$t("Sync process initiated successfully.")
                : this.$t("Failed to initiate sync process.");
            const type = data.status ? 'success' : 'error';
            this.ShowAlert(
                message,
                type,
                true,
                this.$t('Alert')
            );
        }
    },
    computed: {
        isOffline() {
            return this.deviceForm.online === false;
        }
    },

    mounted() {
        // Example existing device data
        this.deviceForm = { ...this.deviceRecord };
        this.getSchedule();
    },
    methods: {
        async getSchedule() {
            this.$socket.emit("getSchedule", { requestedBy: this.$socket.id, deviceId: this.deviceForm.uniqueCode });
            this.$socket.emit("getlogs", { requestedBy: this.$socket.id, deviceId: this.deviceForm.uniqueCode });
            this.$socket.emit("getDeviceLogs", { requestedBy: this.$socket.id, deviceId: this.deviceForm.uniqueCode });
        },
        refresh() {
            this.$socket.emit("getlogs", { requestedBy: this.$socket.id, deviceId: this.deviceForm.uniqueCode });
        },
        refreshDevice() {
            this.$socket.emit("getDeviceLogs", { requestedBy: this.$socket.id, deviceId: this.deviceForm.uniqueCode });
        },
        handleClose() {
            this.$emit("close");
        },
        validateForm() {
            this.errors = {};

            if (!this.deviceForm.deviceName) {
                this.errors.deviceName = 'Device name is required';
            }
            if (!this.deviceForm.uniqueCode) {
                this.errors.uniqueCode = 'Device ID is required';
            }
            if (!this.deviceForm.subLocation) {
                this.errors.subLocation = 'Location is required';
            }
            if (!this.deviceForm.apiUrl) {
                //this.errors.apiUrl = 'Face Auth URL is required';
            } else if (!/^https?:\/\//i.test(this.deviceForm.apiUrl)) {
                this.errors.apiUrl = 'Invalid URL format';
            }
            return Object.keys(this.errors).length === 0;
        },
        clearError(field) {
            if (this.errors[field]) {
                this.$delete(this.errors, field);
            }
        },
        forceRun(row) {
            this.$socket.emit('forcefullyRun', { deviceId: this.deviceForm.uniqueCode, requestedBy: this.$socket.id, id: row.id });
        },
        filterLogs() {

            if (!this.selectedDate) {
                this.logs = [...this.allLogs];
                return;
            }

            // Convert selectedDate to YYYY-MM-DD
            const selected = new Date(this.selectedDate);
            const formattedDate =
                selected.getFullYear() + '-' +
                String(selected.getMonth() + 1).padStart(2, '0') + '-' +
                String(selected.getDate()).padStart(2, '0');



            this.logs = this.allLogs.filter(log => {
                const logDateMatch = log.match(/\d{4}-\d{2}-\d{2}/);
                return logDateMatch && logDateMatch[0] === formattedDate;
            });
        },
        filterDeviceLogs() {

            if (!this.selectedDeviceDate) {
                this.deviceLogs = [...this.allDeviceLogs];
                return;
            }

            // Convert selectedDate to YYYY-MM-DD
            const selected = new Date(this.selectedDeviceDate);
            const formattedDate =
                selected.getFullYear() + '-' +
                String(selected.getMonth() + 1).padStart(2, '0') + '-' +
                String(selected.getDate()).padStart(2, '0');



            this.deviceLogs = this.allDeviceLogs.filter(log => {
                const logDateMatch = log.match(/\d{4}-\d{2}-\d{2}/);
                return logDateMatch && logDateMatch[0] === formattedDate;
            });
        },
        downloadDeviceLogs() {

            if (!this.DeviceLogs || this.DeviceLogs.length === 0) {
                this.ShowAlert(
                    "No logs available to download",
                    "warning",
                    true,
                    "Alert"
                );
                return;
            }

            // Convert logs array to text
            const logContent = this.DeviceLogs.join("\n");

            // Create blob
            const blob = new Blob([logContent], { type: "text/plain;charset=utf-8;" });

            // Create download link
            const link = document.createElement("a");
            const url = URL.createObjectURL(blob);

            link.setAttribute("href", url);
            link.setAttribute(
                "download",
                `device_logs_${this.deviceForm.uniqueCode}_${new Date().toISOString()}.txt`
            );

            document.body.appendChild(link);
            link.click();

            document.body.removeChild(link);
            URL.revokeObjectURL(url);
        },
        downloadLogs() {

            if (!this.logs || this.logs.length === 0) {
                this.ShowAlert(
                    "No logs available to download",
                    "warning",
                    true,
                    "Alert"
                );
                return;
            }

            // Convert logs array to text
            const logContent = this.logs.join("\n");

            // Create blob
            const blob = new Blob([logContent], { type: "text/plain;charset=utf-8;" });

            // Create download link
            const link = document.createElement("a");
            const url = URL.createObjectURL(blob);

            link.setAttribute("href", url);
            link.setAttribute(
                "download",
                `device_logs_${this.deviceForm.uniqueCode}_${new Date().toISOString()}.txt`
            );

            document.body.appendChild(link);
            link.click();

            document.body.removeChild(link);
            URL.revokeObjectURL(url);
        },
        async submitForm() {
            if (!this.validateForm()) {
                this.activeTab = 'details';
                return;
            }

            try {
                this.$socket.emit("activeStatus", {
                    deviceId: this.deviceForm.uniqueCode,
                    statusId: this.deviceForm.statusId,
                    apiUrl: this.deviceForm.apiUrl
                })
                //this.deviceForm.apiUrl = null
                const result = await DataService.DeviceRegister(this.deviceForm);
                // Emit success result
                this.$emit('submitRecord', this.deviceForm);
                this.ShowAlert(
                    this.$t("Deviceupdatedsuccessfully"),
                    'success',
                    true,
                    this.$t('Alert')
                );
            } catch (error) {
                //console.error("Device update failed:", error);
                // Optional: show API error message if available
                const message =
                    error?.response?.data?.message ||
                    this.$t("ErrorWhileProcessingRequest");
                this.ShowAlert(
                    message,
                    'error',
                    true,
                    this.$t('Alert')
                );
            }
        }
    }
}
</script>
